   667	
   668	  const patterns = [
   669	    /\b(latest|current|today|recent|news|price|weather|release date|version|changelog)\b/i,
   670	    /\b(search|find|look up|google|web|internet)\b/i,
   671	    /\b202[5-9]\b/,
   672	    /(актуальн|сейчас|сегодня|новост|последн|свеж|курс|цена|погода|релиз|верси|обновл)/i,
   673	    /(найди|поищи|загугли|посмотри в интернете|в сети|вебе|интернет)/i,
   674	    /(что известно|дай информацию|проверь|сравни цены|какая сейчас|какой сейчас)/i
   675	  ];
   676	
   677	  return patterns.some((pattern) => pattern.test(normalized));
