   800	
   801	    const redraw = (): void => {
   802	      renderPrompt(buffer);
   803	    };
   804	
   805	    const appendText = (text: string): void => {
   806	      buffer += text;
   807	      redraw();
   808	    };
   809	
   810	    const appendImage = async (): Promise<boolean> => {
   811	      try {
