   923	async function askRaya(): Promise<RayaResponse> {
   924	  const requestStartedAt = Date.now();
   925	  const inputTokens = estimateMessagesTokens(messages);
   926	  const stopThinkingTimer = startThinkingTimer();
   927	  let startedStreaming = false;
   928	  let answer = "";
   929	
   930	  try {
   931	    let stream: AsyncIterable<OpenAI.Chat.Completions.ChatCompletionChunk> | undefined;
   932	
   933	    for (let attempt = 1; attempt <= maxRetryAttempts; attempt += 1) {
   934	      try {
   935	        stream = (await client.chat.completions.create({
   936	          model: currentModel,
   937	          messages,
   938	          temperature: 0.7,
   939	          stream: true
   940	        })) as AsyncIterable<OpenAI.Chat.Completions.ChatCompletionChunk>;
   941	        break;
   942	      } catch (error) {
   943	        if (attempt >= maxRetryAttempts || !isRetryableError(error)) {
   944	          throw error;
   945	        }
   946	
   947	        await delay(initialRetryDelayMs * attempt);
   948	      }
   949	    }
   950	
   951	    if (!stream) {
   952	      throw new Error("Model stream was not created.");
   953	    }
   954	
   955	    for await (const chunk of stream) {
   956	      const content = chunk.choices[0]?.delta?.content ?? "";
   957	
   958	      if (!content) {
   959	        continue;
   960	      }
   961	
   962	      if (!startedStreaming) {
   963	        const elapsed = stopThinkingTimer();
   964	        console.log(`${color("thinking", theme.orange)} ${color(`${elapsed.toFixed(1)}s`, theme.blue)}`);
   965	        output.write(`${color("raya", theme.cyan)} ${color("›", theme.muted)} `);
   966	        startedStreaming = true;
   967	      }
   968	
   969	      output.write(content);
   970	      answer += content;
   971	    }
   972	
   973	    if (!startedStreaming) {
   974	      const elapsed = stopThinkingTimer();
   975	      console.log(`${color("thinking", theme.orange)} ${color(`${elapsed.toFixed(1)}s`, theme.blue)}`);
   976	    }
   977	
   978	    const trimmedAnswer = answer.trim();
   979	    const seconds = (Date.now() - requestStartedAt) / 1000;
   980	
   981	    console.log("\n");
   982	
   983	    return {
   984	      answer: trimmedAnswer,
   985	      inputTokens,
   986	      outputTokens: estimateTokens(trimmedAnswer),
   987	      seconds
   988	    };
   989	  } catch (error) {
   990	    if (!startedStreaming) {
   991	      stopThinkingTimer();
   992	    }
   993	
   994	    throw error;
   995	  }
   996	}
